const crypto = require('crypto');
const payload = JSON.stringify({ prompt: $json.prompt });
const secret = '4286245fa020715c737ae048c4230652bb8dcb8cf51ef94da434fd0c3ac57e46';
const signature = crypto.createHmac('sha256', secret).update(payload).digest('hex');
return [{ body: payload, headers: { 'Content-Type': 'application/json', 'X-Webhook-Signature': signature } }];
